{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOJppGHEt9+JGWLB+u7jQzy"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"colab":{"base_uri":"https://localhost:8080/","height":103},"id":"sVJQ9od8MwOI","executionInfo":{"status":"ok","timestamp":1781492046916,"user_tz":-330,"elapsed":2602,"user":{"displayName":"Venkatarao Pidugu","userId":"16397057302094420254"}},"outputId":"0d2c50f8-d5fd-48e4-b212-108ba8cb1c8a"},"outputs":[{"output_type":"display_data","data":{"text/plain":["<Figure size 1400x500 with 2 Axes>"],"image/png":"\n"},"metadata":{}}],"source":["import pandas as pd\n","import numpy as np\n","import matplotlib.pyplot as plt\n","import seaborn as sns\n","\n","# --- 1. GENERATE FAKE DATASET ---\n","# This simulates a dataset of 500 people so you have data to work with\n","np.random.seed(42) # Ensures the random data looks the same every time you run it\n","\n","fake_data = {\n","    'Age': np.random.randint(10, 80, size=500), # Random ages between 10 and 80\n","    'Gender': np.random.choice(['Male', 'Female', 'Others'], size=500, p=[0.48, 0.48, 0.04]) # Random genders\n","}\n","df = pd.DataFrame(fake_data)\n","\n","\n","# --- 2. PREPARE THE GENDER DATA ---\n","gender_counts = df['Gender'].value_counts().reset_index()\n","gender_counts.columns = ['Gender Category', 'Count of People']\n","\n","\n","# --- 3. INITIALIZE PLOT ---\n","# Creating a 1x2 grid to hold both the Age and Gender plots side-by-side\n","fig, axes = plt.subplots(1, 2, figsize=(14, 5))\n","\n","\n","# --- 4. PLOT 1: AGE DISTRIBUTION (Left Side) ---\n","sns.histplot(data=df, x='Age', kde=True, ax=axes[0], color='#b366b3') # Match the purple theme\n","axes[0].set_title(\"Age Distribution (Histogram)\")\n","axes[0].set_xlabel(\"Age Groups\")\n","axes[0].set_ylabel(\"Count of People\")\n","\n","\n","# --- 5. PLOT 2: GENDER DISTRIBUTION (Right Side) ---\n","sns.barplot(\n","    data=gender_counts,\n","    x=\"Gender Category\",\n","    y=\"Count of People\",\n","    hue=\"Gender Category\",\n","    palette=\"magma\",       # Dark purple to orange palette\n","    legend=False,\n","    ax=axes[1]\n",")\n","axes[1].set_title(\"Gender Distribution (Bar Chart)\")\n","axes[1].set_xlabel(\"Gender Category\")\n","axes[1].set_ylabel(\"Count of People\")\n","\n","\n","# --- 6. DISPLAY BOTH PLOTS ---\n","plt.tight_layout()\n","plt.show()"]}]}